import { Injectable } from '@nestjs/common';
import { OrderDto } from '../dto/order.dto';
import { ProcessedOrder } from '../interfaces/processed-order.interface';
import { PricingService } from './pricing.service';

@Injectable()
export class OrderService {
  constructor(private readonly pricingService: PricingService) {}

  async processOrders(orders: OrderDto[]): Promise<ProcessedOrder[]> {
    const priced = await this.pricingService.calculateBatch(orders);
    return priced.items.map((item: any) => ({
      orderId: item.id,
      total: item.price * item.quantity,
      currency: item.currency,
      status: 'processed',
    }));
  }

  async getOrderSummary(orderId: string): Promise<OrderSummary> {
    const order = await this.fetchOrder(orderId);
    return {
      ...order,
      lineItems: order.lineItems.map((li: LineItem) => ({
        ...li,
        subtotal: li.unitPrice * li.quantity,
      })),
    };
  }
}

import { Injectable } from '@nestjs/common';
import { PricingClient } from '../clients/pricing.client';

@Injectable()
export class PricingService {
  constructor(private readonly client: PricingClient) {}

  async calculateBatch(orders: OrderDto[]) {
    const response = await this.client.batchPrice({
      orders: orders.map(o => ({
        sku: o.sku,
        quantity: o.quantity,
        customerId: o.customerId,
      })),
    });
    return response;
  }
}

import { HttpClient } from '@nestjs/common';

export class PricingClient {
  constructor(private readonly http: HttpClient) {}

  async batchPrice(body: { orders: any[] }) {
    const res = await this.http.post('/api/v2/pricing/batch', body).toPromise();
    return res.data;
  }
}

import { Test } from '@nestjs/testing';
import { OrderService } from '../order.service';
import { PricingService } from '../../services/pricing.service';

describe('OrderService', () => {
  let service: OrderService;
  let pricingService: jest.Mocked<PricingService>;

  beforeEach(async () => {
    const module = await Test.createTestingModule({
      providers: [
        OrderService,
        {
          provide: PricingService,
          useValue: {
            calculateBatch: jest.fn(),
          },
        },
      ],
    }).compile();

    service = module.get(OrderService);
    pricingService = module.get(PricingService);
  });

  describe('processOrders', () => {
    it('should process a list of orders', async () => {
      const orders = [
        { id: '1', sku: 'ABC', quantity: 2, customerId: 'cust-1' },
        { id: '2', sku: 'XYZ', quantity: 1, customerId: 'cust-2' },
      ];

      pricingService.calculateBatch.mockResolvedValue({
        results: [
          { id: '1', price: 10.0, quantity: 2, currency: 'USD' },
          { id: '2', price: 25.0, quantity: 1, currency: 'USD' },
        ],
      });

      const result = await service.processOrders(orders);

      expect(result).toHaveLength(2);
      expect(result[0]).toEqual({
        orderId: '1',
        total: 20.0,
        currency: 'USD',
        status: 'processed',
      });
    });
  });
});
